      ('ruby-of-the-war-mage', 'Рубин боевого мага', 'Испещрённый магическими рунами, этот рубин диаметром 1 дюйм (2,5 см) позволяет использовать простое или воинское оружие в качестве заклинательной фокусировки. Чтобы это сделать, вы должны прикрепить рубин к оружию, прижимая его к оружию не менее 10 минут. После этого удалить рубин можно будет только действием или уничтожив оружие. Даже [преграда магии [antimagic field]](/spells/263-antimagic_field/) не заставит его отсоединиться. Рубин падает с оружия, если ваша настройка на него оканчивается.', 'wondrous', 'common', null, null, null, true, 'https://dnd.su/items/422-ruby-of-the-war-mage/', 'Xanathar''s Guide to Everything'),
      ('shield-of-expression', 'Щит экспрессии', 'Передняя сторона щита имеет форму лица. Когда вы носите щит, вы можете бонусным действием поменять выражение лица на нём.', 'armor', 'common', null, null, 'shield', false, 'https://dnd.su/items/440-shield-of-expression/', 'Xanathar''s Guide to Everything'),
      ('smoldering-armor', 'Дымящий доспех', 'Когда этот доспех надет, он источает клубы не имеющего запаха безвредного дыма.', 'armor', 'common', null, null, 'body', false, 'https://dnd.su/items/398-smoldering-armor/', 'Xanathar''s Guide to Everything'),
      ('staff-of-adornment', 'Посох украшения', 'Если вы размещаете объект, весящий не более 1 фунта (такой как осколок кристалла, яйцо или камень) выше навершия посоха, пока держите его, объект поднимается на дюйм от навершия посоха и остаётся там до тех пор, пока не будет перемещён или пока посох находится у вас. Посох может одновременно удерживать до трёх таких объектов плавающими над его навершием. Пока вы держите посох, вы можете заставить один или несколько объектов медленно вращаться вокруг своей оси или вокруг друг друга.', 'magic-item', 'common', null, null, null, false, 'https://dnd.su/items/418-staff-of-adornment/', 'Xanathar''s Guide to Everything'),
      ('staff-of-birdcalls', 'Посох птичьего щебета', 'Этот деревянный посох украшен резьбой в виде птиц. У него 10 зарядов. Держа посох, вы можете действием потратить один заряд и создать на расстоянии до 60 футов один из следующих звуков: чириканье вьюрка, карканье ворона, кряканье утки, кудахтанье курицы, гогот гуся, клич гагары, кулдыканье индюка, плач чайки, уханье совы или крик орла. Посох ежедневно восстанавливает 1к6 +4 заряда на рассвете. Если вы потратили последний заряд, бросьте к20. Если выпадет 1, посох взрывается безвредным облаком птичьих перьев и пропадает навсегда.', 'magic-item', 'common', null, null, null, false, 'https://dnd.su/items/417-staff-of-birdcalls/', 'Xanathar''s Guide to Everything'),
      ('staff-of-flowers', 'Посох цветов', 'У этого деревянного посоха 10 зарядов. Держа посох, вы можете действием потратить один заряд. Пробуждённый силой посоха цветок вырастет на почве или грязи в пределах 5 футов от вас или на самом посохе. Если вы не выбрали тип цветка, посох создаёт маргаритку с лёгким запахом. Цветок безвредный и немагический. Он растёт и увядает как обычный цветок.

Посох ежедневно восстанавливает 1к6 +4 заряда на рассвете. Если вы потратили последний заряд, бросьте к20. Если выпадет 1, посох превращается в лепестки цветов и пропадает навсегда.', 'magic-item', 'common', null, null, null, false, 'https://dnd.su/items/419-staff-of-flowers/', 'Xanathar''s Guide to Everything'),
      ('talking-doll', 'Говорящая кукла', 'Пока кукла находится в пределах 5 футов от вас, вы можете во время короткого отдыха сказать ей до шести фраз, ни одна из которых не может быть длиннее шести слов, и установить условия, при которых кукла будет говорить каждую фразу. Каким бы ни было условие, оно должно совершиться в пределах 5 футов от куклы, чтобы она заговорила. Например, когда кто-то поднимет куклу, она может сказать: «Я хочу конфетку». Фразы куклы теряются, когда ваша настройка на неё заканчивается.', 'wondrous', 'common', null, null, null, true, 'https://dnd.su/items/394-talking-doll/', 'Xanathar''s Guide to Everything'),
      ('tankard-of-sobriety', 'Кружка трезвости', 'На одной стороне этой кружки изображено суровое лицо. Вы можете пить из этой кружки эль, вино или любой другой немагический алкоголь и не пьянеть. Кружка не оказывает никакого эффекта на магический алкоголь и вредные вещества, такие как яд.', 'wondrous', 'common', null, null, null, false, 'https://dnd.su/items/405-tankard-of-sobriety/', 'Xanathar''s Guide to Everything'),
      ('unbreakable-arrow', 'Несломимая стрела', 'Эта стрела не может быть сломана, кроме как в области действия [преграды магии [antimagic field]](/spells/263-antimagic_field/).', 'weapon', 'common', null, null, '1-handed', false, 'https://dnd.su/items/407-unbreakable-arrow/', 'Xanathar''s Guide to Everything'),
      ('veterans-cane', 'Трость ветерана', 'Когда вы сжимаете эту трость и бонусным действием произносите командное слово, трость превращается в обычный длинный меч и перестаёт быть магической.', 'wondrous', 'common', null, null, null, false, 'https://dnd.su/items/433-veterans-cane/', 'Xanathar''s Guide to Everything'),
      ('walloping-ammunition', 'Опрокидывающий боеприпас', 'Этот боеприпас содержит в себе скрытый сильный удар. Существо, в которое попал такой боеприпас, должно преуспеть в спасброске Силы Сл 10, иначе будет сбито с ног.', 'weapon', 'common', null, null, '1-handed', false, 'https://dnd.su/items/408-walloping-ammunition/', 'Xanathar''s Guide to Everything'),
      ('wand-of-conducting', 'Дирижёрская палочка', 'У этой волшебной палочки 3 заряда. Если вы её держите, вы можете действием потратить 1 заряд, чтобы создать оркестровую музыку, размахивая ею. Музыку слышно на расстоянии 60 футов, и она заканчивается, когда вы перестанете размахивать палочкой.

Палочка ежедневно восстанавливает все заряды на рассвете. Если вы потратили последний заряд, бросьте к20. Если выпадет 1, играет грустный тромбон, а палочка рассыпается в пыль и уничтожается.', 'magic-item', 'common', null, null, null, false, 'https://dnd.su/items/396-wand-of-conducting/', 'Xanathar''s Guide to Everything'),
      ('wand-of-pyrotechnics', 'Палочка пиротехники', 'У этой волшебной палочки 7 зарядов. Если вы её держите, вы можете действием потратить 1 заряд, чтобы создать безвредную разноцветную вспышку света в точке в пределах 60 футов. Эта вспышка сопровождается потрескивающим шумом, слышимым на расстоянии 300 футов. Свет такой же яркий, как пламя факела, но длится всего секунду.

Палочка ежедневно восстанавливает 1к6+1 заряд на рассвете. Если вы потратили последний заряд, бросьте к20. Если выпадет 1, палочка взрывается безвредным пиротехническим всполохом и уничтожается.', 'magic-item', 'common', null, null, null, false, 'https://dnd.su/items/411-wand-of-pyrotechnics/', 'Xanathar''s Guide to Everything'),
      ('wand-of-scowls', 'Палочка хмурых взглядов', 'У этой волшебной палочки 3 заряда. Если вы её держите, вы можете действием потратить 1 заряд и выбрать в качестве цели гуманоида, которого видите в пределах 30 футов. Цель должна преуспеть в спасброске Харизмы Сл 10, иначе она будет хмуриться 1 минуту.

Палочка восстанавливает все заряды на рассвете. Если вы потратили последний заряд, бросьте к20. Если выпадет 1, палочка превращается в [палочку улыбок [Wand of Smiles]](/items/412-wand_of_smiles/).', 'magic-item', 'common', null, null, null, false, 'https://dnd.su/items/413-wand-of-scowls/', 'Xanathar''s Guide to Everything'),
      ('wand-of-smiles', 'Палочка улыбок', 'У этой волшебной палочки 3 заряда. Если вы её держите, вы можете действием потратить 1 заряд и выбрать в качестве цели гуманоида, которого видите в пределах 30 футов. Цель должна преуспеть в спасброске Харизмы Сл 10, иначе она будет улыбаться 1 минуту. Палочка восстанавливает все заряды на рассвете. Если вы потратили последний заряд, бросьте к20. Если выпадет 1, палочка превращается в [палочку хмурых взглядов [Wand of Scowls]](/items/413-wand_of_scowls/).', 'magic-item', 'common', null, null, null, false, 'https://dnd.su/items/412-wand-of-smiles/', 'Xanathar''s Guide to Everything')
    ),
    typed_seed as (
      select
        srd_slug::text,
        title_ru::text,
        description_ru::text,
        category::text,
        rarity::text,
        price_gp::numeric,
        weight_lb::numeric,
        slot::text,
        requires_attunement::boolean,
        dndsu_url::text,
        source_detail::text
      from seed
    ),
    inserted as (
      insert into nodes (campaign_id, type_id, title, fields)
      select
        c_rec.id,
        type_id_v,
        s.title_ru,
        jsonb_strip_nulls(jsonb_build_object(
          'srd_slug', s.srd_slug,
          'description', s.description_ru,
          'dndsu_url', s.dndsu_url,
          'source_detail', s.source_detail
        ))
      from typed_seed s
      where not exists (
        select 1 from nodes n
        where n.campaign_id = c_rec.id
          and n.fields->>'srd_slug' = s.srd_slug
      )
      returning id, fields->>'srd_slug' as srd_slug
    )
    insert into item_attributes (
      node_id, category_slug, rarity, price_gp, weight_lb,
      slot_slug, requires_attunement,
      source_slug, availability_slug
    )
    select
      i.id, s.category, s.rarity, s.price_gp, s.weight_lb,
      s.slot, s.requires_attunement,
      'srd-5e', null
    from inserted i
    join typed_seed s on s.srd_slug = i.srd_slug
    on conflict (node_id) do nothing;

    get diagnostics ins_count = row_count;
    raise notice 'Campaign % (%): inserted % new dnd.su items (Xanathar''s Guide to Everything)',
      c_rec.slug, c_rec.id, ins_count;
  end loop;
end $$;

-- Phase 2 backfill (transactions.item_node_id = N) is intentionally
-- omitted for dnd.su entries: the canonical Russian title is shared
-- across many similar items and would mis-link prior transactions.
-- DMs do per-item linking on demand from the catalog UI.

commit;
